import React, { useLayoutEffect, useState } from "react";
import axios from "axios";
import { Table, Button, Checkbox } from "semantic-ui-react";
import { useEquipmentInfoRecordTableHooks } from "./equipment-info-record-table-hooks";

const EquipmentInfoRecordTable = () => {
  const equipmentInfo = useEquipmentInfoRecordTableHooks();

  return (
    <div title="Equipment Info Record Table">
      <Table selectable sortable>
        <Table.Header>
          <Table.Row>
            <Table.HeaderCell>ID</Table.HeaderCell>
            <Table.HeaderCell>Serial</Table.HeaderCell>
            <Table.HeaderCell>Asset Number</Table.HeaderCell>
            <Table.HeaderCell>Health Score</Table.HeaderCell>
            <Table.HeaderCell>Brand</Table.HeaderCell>
            <Table.HeaderCell>Model</Table.HeaderCell>
            <Table.HeaderCell>Hospital</Table.HeaderCell>
            <Table.HeaderCell>Edit</Table.HeaderCell>
          </Table.Row>
        </Table.Header>
        <Table.Body>
          {equipmentInfo.map((part) => (
            <Table.Row key={part.id}>
              <Table.Cell>{part.id}</Table.Cell>
              <Table.Cell>{part.serial}</Table.Cell>
              <Table.Cell>{part.assetNumber}</Table.Cell>
              <Table.Cell>{part.healthScore}</Table.Cell>
              <Table.Cell>{part.brand}</Table.Cell>
              <Table.Cell>{part.model}</Table.Cell>
              <Table.Cell>{part.hospital}</Table.Cell>
              <Table.Cell>
                <Button.Group>
                  <Button>Edit</Button>
                </Button.Group>
              </Table.Cell>
            </Table.Row>
          ))}
        </Table.Body>
      </Table>
    </div>
  );
};

export default EquipmentInfoRecordTable;
